@@ -0,0 +1,1733 @@
+/*
+ * YFS Server (yfs.c)
+ *
+ * Yalnix File System server process.  Runs as the init process,
+ * registers as FILE_SERVER, forks/execs the first client, then
+ * enters a Receive/dispatch/Reply loop.
+ *
+ * Implements block cache (32 entries) and inode cache (16 entries),
+ * both with write-back LRU eviction.  Inode writeback goes through
+ * the block cache as specified.
+ */
+
+#include <comp421/filesystem.h>
+#include <comp421/yalnix.h>
+#include <comp421/iolib.h>
+#include <string.h>
+#include <stdlib.h>
+
+#include "yfs.h"
+
+/* ================================================================== */
+/*                        CONSTANTS                                    */
+/* ================================================================== */
+
+#define INODES_PER_BLOCK  (BLOCKSIZE / INODESIZE)
+#define ENTRIES_PER_BLOCK (BLOCKSIZE / (int)sizeof(struct dir_entry))
+#define PTRS_PER_BLOCK    (BLOCKSIZE / (int)sizeof(int))
+#define MAX_FILE_SIZE     ((NUM_DIRECT + PTRS_PER_BLOCK) * BLOCKSIZE)
+
+/* ================================================================== */
+/*                     GLOBAL FILE SYSTEM STATE                        */
+/* ================================================================== */
+
+static int g_num_inodes;
+static int g_num_blocks;
+static int g_first_data_block;
+
+/* Free inode stack */
+static int g_free_inodes[NUMSECTORS];
+static int g_num_free_inodes;
+
+/* Free block stack */
+static int g_free_blocks[NUMSECTORS];
+static int g_num_free_blocks;
+
+/* ================================================================== */
+/*                        BLOCK CACHE                                  */
+/* ================================================================== */
+
+#define BHASH_SIZE BLOCK_CACHESIZE
+
+struct bcache_entry {
+    int blocknum;          /* -1 = unused */
+    int dirty;
+    char data[BLOCKSIZE];
+    int hash_next;         /* index in bcache[], -1 = end */
+    int hash_prev;
+    int lru_next;          /* toward tail (least recent) */
+    int lru_prev;          /* toward head (most recent) */
+};
+
+static struct bcache_entry bcache[BLOCK_CACHESIZE];
+static int bhash[BHASH_SIZE];
+static int blru_head = -1, blru_tail = -1;
+
+static void bcache_init(void)
+{
+    int i;
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        bcache[i].blocknum = -1;
+        bcache[i].dirty = 0;
+        bcache[i].hash_next = bcache[i].hash_prev = -1;
+        bcache[i].lru_next  = bcache[i].lru_prev  = -1;
+    }
+    for (i = 0; i < BHASH_SIZE; i++)
+        bhash[i] = -1;
+    blru_head = blru_tail = -1;
+}
+
+/* --- LRU helpers --- */
+
+static void blru_remove(int idx)
+{
+    if (bcache[idx].lru_prev != -1)
+        bcache[bcache[idx].lru_prev].lru_next = bcache[idx].lru_next;
+    else
+        blru_head = bcache[idx].lru_next;
+
+    if (bcache[idx].lru_next != -1)
+        bcache[bcache[idx].lru_next].lru_prev = bcache[idx].lru_prev;
+    else
+        blru_tail = bcache[idx].lru_prev;
+
+    bcache[idx].lru_prev = bcache[idx].lru_next = -1;
+}
+
+static void blru_push_head(int idx)
+{
+    bcache[idx].lru_prev = -1;
+    bcache[idx].lru_next = blru_head;
+    if (blru_head != -1)
+        bcache[blru_head].lru_prev = idx;
+    blru_head = idx;
+    if (blru_tail == -1)
+        blru_tail = idx;
+}
+
+static void blru_touch(int idx)
+{
+    blru_remove(idx);
+    blru_push_head(idx);
+}
+
+/* --- Hash helpers --- */
+
+static void bhash_remove(int idx)
+{
+    int h = bcache[idx].blocknum % BHASH_SIZE;
+    if (bcache[idx].hash_prev != -1)
+        bcache[bcache[idx].hash_prev].hash_next = bcache[idx].hash_next;
+    else
+        bhash[h] = bcache[idx].hash_next;
+    if (bcache[idx].hash_next != -1)
+        bcache[bcache[idx].hash_next].hash_prev = bcache[idx].hash_prev;
+    bcache[idx].hash_prev = bcache[idx].hash_next = -1;
+}
+
+static void bhash_insert(int idx)
+{
+    int h = bcache[idx].blocknum % BHASH_SIZE;
+    bcache[idx].hash_prev = -1;
+    bcache[idx].hash_next = bhash[h];
+    if (bhash[h] != -1)
+        bcache[bhash[h]].hash_prev = idx;
+    bhash[h] = idx;
+}
+
+static int bhash_find(int blocknum)
+{
+    int h = blocknum % BHASH_SIZE;
+    int idx = bhash[h];
+    while (idx != -1) {
+        if (bcache[idx].blocknum == blocknum)
+            return idx;
+        idx = bcache[idx].hash_next;
+    }
+    return -1;
+}
+
+/* --- Public block cache API --- */
+
+/* Read block into cache (or find existing).  Returns pointer to data. */
+static char *block_read(int blocknum)
+{
+    int idx = bhash_find(blocknum);
+    if (idx != -1) {
+        blru_touch(idx);
+        return bcache[idx].data;
+    }
+
+    /* Need a free slot.  Look for unused first. */
+    int slot = -1;
+    int i;
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        if (bcache[i].blocknum == -1) {
+            slot = i;
+            break;
+        }
+    }
+    if (slot == -1) {
+        /* Evict LRU tail */
+        slot = blru_tail;
+        if (bcache[slot].dirty) {
+            WriteSector(bcache[slot].blocknum, bcache[slot].data);
+            bcache[slot].dirty = 0;
+        }
+        bhash_remove(slot);
+        blru_remove(slot);
+    }
+
+    bcache[slot].blocknum = blocknum;
+    bcache[slot].dirty = 0;
+    ReadSector(blocknum, bcache[slot].data);
+    bhash_insert(slot);
+    blru_push_head(slot);
+    return bcache[slot].data;
+}
+
+/* Allocate a NEW block in cache (zeroed, dirty).  No disk read. */
+static char *block_alloc_cached(int blocknum)
+{
+    int idx = bhash_find(blocknum);
+    if (idx != -1) {
+        blru_touch(idx);
+        memset(bcache[idx].data, 0, BLOCKSIZE);
+        bcache[idx].dirty = 1;
+        return bcache[idx].data;
+    }
+
+    int slot = -1;
+    int i;
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        if (bcache[i].blocknum == -1) { slot = i; break; }
+    }
+    if (slot == -1) {
+        slot = blru_tail;
+        if (bcache[slot].dirty) {
+            WriteSector(bcache[slot].blocknum, bcache[slot].data);
+            bcache[slot].dirty = 0;
+        }
+        bhash_remove(slot);
+        blru_remove(slot);
+    }
+
+    bcache[slot].blocknum = blocknum;
+    bcache[slot].dirty = 1;
+    memset(bcache[slot].data, 0, BLOCKSIZE);
+    bhash_insert(slot);
+    blru_push_head(slot);
+    return bcache[slot].data;
+}
+
+static void block_mark_dirty(int blocknum)
+{
+    int idx = bhash_find(blocknum);
+    if (idx != -1) bcache[idx].dirty = 1;
+}
+
+static void bcache_sync(void)
+{
+    int i;
+    for (i = 0; i < BLOCK_CACHESIZE; i++) {
+        if (bcache[i].blocknum != -1 && bcache[i].dirty) {
+            WriteSector(bcache[i].blocknum, bcache[i].data);
+            bcache[i].dirty = 0;
+        }
+    }
+}
+
+/* ================================================================== */
+/*                        INODE CACHE                                  */
+/* ================================================================== */
+
+#define IHASH_SIZE INODE_CACHESIZE
+
+struct icache_entry {
+    int inum;             /* -1 = unused */
+    int dirty;
+    struct inode in;
+    int hash_next, hash_prev;
+    int lru_next, lru_prev;
+};
+
+static struct icache_entry icache[INODE_CACHESIZE];
+static int ihash[IHASH_SIZE];
+static int ilru_head = -1, ilru_tail = -1;
+
+static void icache_init(void)
+{
+    int i;
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        icache[i].inum = -1;
+        icache[i].dirty = 0;
+        icache[i].hash_next = icache[i].hash_prev = -1;
+        icache[i].lru_next  = icache[i].lru_prev  = -1;
+    }
+    for (i = 0; i < IHASH_SIZE; i++)
+        ihash[i] = -1;
+    ilru_head = ilru_tail = -1;
+}
+
+/* --- LRU helpers --- */
+
+static void ilru_remove(int idx)
+{
+    if (icache[idx].lru_prev != -1)
+        icache[icache[idx].lru_prev].lru_next = icache[idx].lru_next;
+    else
+        ilru_head = icache[idx].lru_next;
+
+    if (icache[idx].lru_next != -1)
+        icache[icache[idx].lru_next].lru_prev = icache[idx].lru_prev;
+    else
+        ilru_tail = icache[idx].lru_prev;
+
+    icache[idx].lru_prev = icache[idx].lru_next = -1;
+}
+
+static void ilru_push_head(int idx)
+{
+    icache[idx].lru_prev = -1;
+    icache[idx].lru_next = ilru_head;
+    if (ilru_head != -1)
+        icache[ilru_head].lru_prev = idx;
+    ilru_head = idx;
+    if (ilru_tail == -1)
+        ilru_tail = idx;
+}
+
+static void ilru_touch(int idx)
+{
+    ilru_remove(idx);
+    ilru_push_head(idx);
+}
+
+/* --- Hash helpers --- */
+
+static void ihash_remove(int idx)
+{
+    int h = icache[idx].inum % IHASH_SIZE;
+    if (icache[idx].hash_prev != -1)
+        icache[icache[idx].hash_prev].hash_next = icache[idx].hash_next;
+    else
+        ihash[h] = icache[idx].hash_next;
+    if (icache[idx].hash_next != -1)
+        icache[icache[idx].hash_next].hash_prev = icache[idx].hash_prev;
+    icache[idx].hash_prev = icache[idx].hash_next = -1;
+}
+
+static void ihash_insert(int idx)
+{
+    int h = icache[idx].inum % IHASH_SIZE;
+    icache[idx].hash_prev = -1;
+    icache[idx].hash_next = ihash[h];
+    if (ihash[h] != -1)
+        icache[ihash[h]].hash_prev = idx;
+    ihash[h] = idx;
+}
+
+static int ihash_find(int inum)
+{
+    int h = inum % IHASH_SIZE;
+    int idx = ihash[h];
+    while (idx != -1) {
+        if (icache[idx].inum == inum) return idx;
+        idx = icache[idx].hash_next;
+    }
+    return -1;
+}
+
+/* Write dirty inode through block cache */
+static void inode_writeback(int cidx)
+{
+    int inum  = icache[cidx].inum;
+    int blk   = 1 + inum / INODES_PER_BLOCK;
+    int off   = (inum % INODES_PER_BLOCK) * INODESIZE;
+    char *bd  = block_read(blk);
+    memcpy(bd + off, &icache[cidx].in, sizeof(struct inode));
+    block_mark_dirty(blk);
+    icache[cidx].dirty = 0;
+}
+
+/* --- Public inode cache API --- */
+
+static struct inode *inode_read(int inum)
+{
+    int idx = ihash_find(inum);
+    if (idx != -1) {
+        ilru_touch(idx);
+        return &icache[idx].in;
+    }
+
+    int slot = -1;
+    int i;
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        if (icache[i].inum == -1) { slot = i; break; }
+    }
+    if (slot == -1) {
+        slot = ilru_tail;
+        if (icache[slot].dirty)
+            inode_writeback(slot);
+        ihash_remove(slot);
+        ilru_remove(slot);
+    }
+
+    icache[slot].inum  = inum;
+    icache[slot].dirty = 0;
+
+    int blk  = 1 + inum / INODES_PER_BLOCK;
+    int off  = (inum % INODES_PER_BLOCK) * INODESIZE;
+    char *bd = block_read(blk);
+    memcpy(&icache[slot].in, bd + off, sizeof(struct inode));
+
+    ihash_insert(slot);
+    ilru_push_head(slot);
+    return &icache[slot].in;
+}
+
+static void inode_mark_dirty(int inum)
+{
+    int idx = ihash_find(inum);
+    if (idx != -1) icache[idx].dirty = 1;
+}
+
+static void icache_sync(void)
+{
+    int i;
+    for (i = 0; i < INODE_CACHESIZE; i++) {
+        if (icache[i].inum != -1 && icache[i].dirty)
+            inode_writeback(i);
+    }
+}
+
+/* Full sync: inodes first (goes through block cache), then blocks. */
+static void full_sync(void)
+{
+    icache_sync();
+    bcache_sync();
+}
+
+/* ================================================================== */
+/*                    FREE LIST MANAGEMENT                             */
+/* ================================================================== */
+
+static int alloc_inode(void)
+{
+    if (g_num_free_inodes == 0) return 0;
+    return g_free_inodes[--g_num_free_inodes];
+}
+
+static void release_inode(int inum)
+{
+    g_free_inodes[g_num_free_inodes++] = inum;
+}
+
+static int alloc_block(void)
+{
+    if (g_num_free_blocks == 0) return 0;
+    int bn = g_free_blocks[--g_num_free_blocks];
+    block_alloc_cached(bn);   /* zero-filled, dirty */
+    return bn;
+}
+
+static void release_block(int bn)
+{
+    g_free_blocks[g_num_free_blocks++] = bn;
+}
+
+/* ================================================================== */
+/*                   BLOCK-NUMBER HELPERS                               */
+/* ================================================================== */
+
+/* Return the disk block number for file block index `idx`. 0 = hole. */
+static int get_blocknum(struct inode *in, int idx)
+{
+    if (idx < NUM_DIRECT)
+        return in->direct[idx];
+
+    if (in->indirect == 0) return 0;
+    char *ib = block_read(in->indirect);
+    int *ptrs = (int *)ib;
+    return ptrs[idx - NUM_DIRECT];
+}
+
+/* Ensure file block `idx` is allocated.  Returns disk block num or 0. */
+static int ensure_block(struct inode *in, int inum, int idx)
+{
+    if (idx < NUM_DIRECT) {
+        if (in->direct[idx] == 0) {
+            int bn = alloc_block();
+            if (bn == 0) return 0;
+            in->direct[idx] = bn;
+            inode_mark_dirty(inum);
+        }
+        return in->direct[idx];
+    }
+
+    /* Need indirect block */
+    if (in->indirect == 0) {
+        int bn = alloc_block();
+        if (bn == 0) return 0;
+        in->indirect = bn;
+        inode_mark_dirty(inum);
+    }
+    char *ib = block_read(in->indirect);
+    int *ptrs = (int *)ib;
+    int slot = idx - NUM_DIRECT;
+    if (ptrs[slot] == 0) {
+        int bn = alloc_block();
+        if (bn == 0) return 0;
+        ptrs[slot] = bn;
+        block_mark_dirty(in->indirect);
+    }
+    return ptrs[slot];
+}
+
+/* ================================================================== */
+/*                    DIRECTORY HELPERS                                 */
+/* ================================================================== */
+
+/* Compare dir_entry name with a C-string target.  Returns 1 on match. */
+static int name_match(const char *dir_name, const char *target)
+{
+    int tlen = strlen(target);
+    if (tlen > DIRNAMELEN) return 0;
+
+    int dlen = 0;
+    while (dlen < DIRNAMELEN && dir_name[dlen] != '\0') dlen++;
+
+    if (dlen != tlen) return 0;
+    return memcmp(dir_name, target, tlen) == 0;
+}
+
+/* Set the name field in a dir_entry (pad with '\0'). */
+static void set_entry_name(struct dir_entry *e, const char *name)
+{
+    int nlen = strlen(name);
+    if (nlen > DIRNAMELEN) nlen = DIRNAMELEN;
+    memcpy(e->name, name, nlen);
+    if (nlen < DIRNAMELEN)
+        memset(e->name + nlen, 0, DIRNAMELEN - nlen);
+}
+
+/* Look up `name` in directory inode `dir_inum`.  Returns inum (>0) or 0. */
+static int dir_lookup(int dir_inum, const char *name)
+{
+    struct inode *din = inode_read(dir_inum);
+    int pos = 0;
+    while (pos < din->size) {
+        int bidx   = pos / BLOCKSIZE;
+        int offset = pos % BLOCKSIZE;
+        int bn = get_blocknum(din, bidx);
+        if (bn == 0) { pos += sizeof(struct dir_entry); continue; }
+        char *bd = block_read(bn);
+        struct dir_entry *e = (struct dir_entry *)(bd + offset);
+        if (e->inum != 0 && name_match(e->name, name))
+            return e->inum;
+        pos += sizeof(struct dir_entry);
+    }
+    return 0;
+}
+
+/* Add entry (name, inum) to directory.  Returns 0 or -1. */
+static int dir_add(int dir_inum, const char *name, int inum)
+{
+    struct inode *din = inode_read(dir_inum);
+    int pos = 0;
+
+    /* Look for a free slot */
+    while (pos < din->size) {
+        int bidx   = pos / BLOCKSIZE;
+        int offset = pos % BLOCKSIZE;
+        int bn = get_blocknum(din, bidx);
+        if (bn != 0) {
+            char *bd = block_read(bn);
+            struct dir_entry *e = (struct dir_entry *)(bd + offset);
+            if (e->inum == 0) {
+                e->inum = (short)inum;
+                set_entry_name(e, name);
+                block_mark_dirty(bn);
+                return 0;
+            }
+        }
+        pos += sizeof(struct dir_entry);
+    }
+
+    /* No free slot — extend directory */
+    int bidx   = din->size / BLOCKSIZE;
+    int offset = din->size % BLOCKSIZE;
+
+    int bn;
+    if (offset == 0) {
+        bn = ensure_block(din, dir_inum, bidx);
+        if (bn == 0) return -1;
+    } else {
+        bn = get_blocknum(din, bidx);
+        if (bn == 0) {
+            bn = ensure_block(din, dir_inum, bidx);
+            if (bn == 0) return -1;
+        }
+    }
+
+    char *bd = block_read(bn);
+    struct dir_entry *e = (struct dir_entry *)(bd + offset);
+    e->inum = (short)inum;
+    set_entry_name(e, name);
+    block_mark_dirty(bn);
+
+    din->size += sizeof(struct dir_entry);
+    inode_mark_dirty(dir_inum);
+    return 0;
+}
+
+/* Remove entry `name` from directory.  Returns 0 or -1. */
+static int dir_remove(int dir_inum, const char *name)
+{
+    struct inode *din = inode_read(dir_inum);
+    int pos = 0;
+    while (pos < din->size) {
+        int bidx   = pos / BLOCKSIZE;
+        int offset = pos % BLOCKSIZE;
+        int bn = get_blocknum(din, bidx);
+        if (bn != 0) {
+            char *bd = block_read(bn);
+            struct dir_entry *e = (struct dir_entry *)(bd + offset);
+            if (e->inum != 0 && name_match(e->name, name)) {
+                e->inum = 0;
+                memset(e->name, 0, DIRNAMELEN);
+                block_mark_dirty(bn);
+                return 0;
+            }
+        }
+        pos += sizeof(struct dir_entry);
+    }
+    return -1;
+}
+
+/* Check if directory has only "." and ".." (and free entries). */
+static int dir_is_empty(int dir_inum)
+{
+    struct inode *din = inode_read(dir_inum);
+    int pos = 0;
+    while (pos < din->size) {
+        int bidx   = pos / BLOCKSIZE;
+        int offset = pos % BLOCKSIZE;
+        int bn = get_blocknum(din, bidx);
+        if (bn != 0) {
+            char *bd = block_read(bn);
+            struct dir_entry *e = (struct dir_entry *)(bd + offset);
+            if (e->inum != 0) {
+                if (!name_match(e->name, ".") && !name_match(e->name, ".."))
+                    return 0;
+            }
+        }
+        pos += sizeof(struct dir_entry);
+    }
+    return 1;
+}
+
+/* ================================================================== */
+/*                    PATHNAME RESOLUTION                               */
+/* ================================================================== */
+
+/* Read symlink data from inode.  Returns length or -1. */
+static int read_symlink(int inum, char *buf, int bufsize)
+{
+    struct inode *in = inode_read(inum);
+    if (in->type != INODE_SYMLINK) return -1;
+    int len = in->size;
+    if (len <= 0) return -1;
+    if (len > bufsize) len = bufsize;
+
+    int done = 0;
+    while (done < len) {
+        int bidx   = done / BLOCKSIZE;
+        int offset = done % BLOCKSIZE;
+        int bn = get_blocknum(in, bidx);
+        if (bn == 0) { done++; continue; }
+        char *bd = block_read(bn);
+        int chunk = BLOCKSIZE - offset;
+        if (chunk > len - done) chunk = len - done;
+        memcpy(buf + done, bd + offset, chunk);
+        done += chunk;
+    }
+    return len;
+}
+
+/*
+ * resolve_path: resolve a pathname to an inode number.
+ *
+ *   path        – null-terminated pathname
+ *   cur_dir     – starting directory inode for relative paths
+ *   follow_last – whether to follow symlinks on the last component
+ *   symcount    – pointer to running symlink traversal count
+ *
+ * Returns inode number on success, or 0 on error.
+ */
+static int resolve_path(const char *path, int cur_dir,
+                        int follow_last, int *symcount)
+{
+    int len = strlen(path);
+    if (len == 0) return 0;
+
+    /* Make a mutable copy; handle trailing slash -> append '.' */
+    char buf[MAXPATHNAMELEN + 2];
+    if (len >= MAXPATHNAMELEN) return 0;
+    memcpy(buf, path, len + 1);
+
+    if (len > 1 && buf[len - 1] == '/') {
+        buf[len]     = '.';
+        buf[len + 1] = '\0';
+        len++;
+    }
+
+    int cur;
+    int pos = 0;
+
+    if (buf[0] == '/') {
+        cur = ROOTINODE;
+        pos = 1;
+    } else {
+        cur = cur_dir;
+    }
+
+    /* Path was "/" (or "///") */
+    if (pos >= len) return cur;
+
+    while (pos < len) {
+        /* skip slashes */
+        while (pos < len && buf[pos] == '/') pos++;
+        if (pos >= len) break;
+
+        /* extract component */
+        int start = pos;
+        while (pos < len && buf[pos] != '/') pos++;
+        int clen = pos - start;
+
+        if (clen > DIRNAMELEN) return 0;
+
+        char comp[DIRNAMELEN + 1];
+        memcpy(comp, buf + start, clen);
+        comp[clen] = '\0';
+
+        /* Is this the last component? */
+        int tmp = pos;
+        while (tmp < len && buf[tmp] == '/') tmp++;
+        int is_last = (tmp >= len);
+
+        /* cur must be a directory */
+        struct inode *cin = inode_read(cur);
+        if (cin->type != INODE_DIRECTORY) return 0;
+
+        /* look up component */
+        int found = dir_lookup(cur, comp);
+        if (found <= 0) return 0;
+
+        struct inode *fin = inode_read(found);
+
+        if (fin->type == INODE_SYMLINK && (!is_last || follow_last)) {
+            if (++(*symcount) > MAXSYMLINKS) return 0;
+            char target[MAXPATHNAMELEN + 1];
+            int tlen = read_symlink(found, target, MAXPATHNAMELEN);
+            if (tlen <= 0) return 0;
+            target[tlen] = '\0';
+
+            int resolved = resolve_path(target, cur, 1, symcount);
+            if (resolved <= 0) return 0;
+
+            if (is_last) return resolved;
+            struct inode *rin = inode_read(resolved);
+            if (rin->type != INODE_DIRECTORY) return 0;
+            cur = resolved;
+        } else {
+            if (is_last) return found;
+            if (fin->type != INODE_DIRECTORY) return 0;
+            cur = found;
+        }
+    }
+
+    return cur;
+}
+
+/*
+ * Split pathname into parent path and last component.
+ * Returns 0 on success, -1 on error.
+ */
+static int split_path(const char *path,
+                      char *parent, char *comp)
+{
+    int len = strlen(path);
+    if (len == 0) return -1;
+
+    /* Strip trailing slashes (but keep at least one char) */
+    int end = len - 1;
+    while (end > 0 && path[end] == '/') end--;
+
+    /* If the whole path is slashes -> parent="/", comp="." */
+    if (end == 0 && path[0] == '/') {
+        strcpy(parent, "/");
+        strcpy(comp, ".");
+        return 0;
+    }
+
+    /* Find last slash before the component */
+    int slash = end;
+    while (slash >= 0 && path[slash] != '/') slash--;
+
+    int name_len = end - slash;
+    if (name_len > DIRNAMELEN) return -1;
+
+    memcpy(comp, path + slash + 1, name_len);
+    comp[name_len] = '\0';
+
+    if (slash < 0) {
+        strcpy(parent, ".");
+    } else if (slash == 0) {
+        strcpy(parent, "/");
+    } else {
+        memcpy(parent, path, slash);
+        parent[slash] = '\0';
+    }
+
+    return 0;
+}
+
+/* ================================================================== */
+/*                  FILE DATA HELPERS                                   */
+/* ================================================================== */
+
+/* Free all data blocks and indirect block for an inode. */
+static void free_file_blocks(int inum)
+{
+    struct inode *in = inode_read(inum);
+    int i;
+
+    for (i = 0; i < NUM_DIRECT; i++) {
+        if (in->direct[i] != 0) {
+            release_block(in->direct[i]);
+            in->direct[i] = 0;
+        }
+    }
+
+    if (in->indirect != 0) {
+        char *ib = block_read(in->indirect);
+        int *ptrs = (int *)ib;
+        for (i = 0; i < PTRS_PER_BLOCK; i++) {
+            if (ptrs[i] != 0)
+                release_block(ptrs[i]);
+        }
+        release_block(in->indirect);
+        in->indirect = 0;
+    }
+
+    in->size = 0;
+    inode_mark_dirty(inum);
+}
+
+/* ================================================================== */
+/*                    MESSAGE HANDLERS                                  */
+/* ================================================================== */
+
+static void handle_open(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    char pathname[MAXPATHNAMELEN];
+    int pathlen = msg->data2;
+
+    memset(&reply, 0, sizeof(reply));
+
+    if (pathlen <= 0 || pathlen > MAXPATHNAMELEN) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    if (CopyFrom(sender, pathname, msg->ptr1, pathlen) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    pathname[pathlen - 1] = '\0';
+
+    int symcount = 0;
+    int inum = resolve_path(pathname, msg->data1, 1, &symcount);
+    if (inum <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *in = inode_read(inum);
+    if (in->type == INODE_FREE) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    reply.data1 = in->size;   /* file size (>= 0 means success) */
+    reply.data2 = inum;
+    reply.data3 = in->reuse;
+    Reply(&reply, sender);
+}
+
+static void handle_create(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    char pathname[MAXPATHNAMELEN];
+    int pathlen = msg->data2;
+
+    memset(&reply, 0, sizeof(reply));
+
+    if (pathlen <= 0 || pathlen > MAXPATHNAMELEN) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    if (CopyFrom(sender, pathname, msg->ptr1, pathlen) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    pathname[pathlen - 1] = '\0';
+
+    char parent_path[MAXPATHNAMELEN];
+    char comp[DIRNAMELEN + 1];
+
+    if (split_path(pathname, parent_path, comp) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    int symcount = 0;
+    int parent_inum = resolve_path(parent_path, msg->data1, 1, &symcount);
+    if (parent_inum <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *pin = inode_read(parent_inum);
+    if (pin->type != INODE_DIRECTORY) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    int existing = dir_lookup(parent_inum, comp);
+
+    if (existing > 0) {
+        struct inode *ein = inode_read(existing);
+
+        /* If last component is a symlink, follow it for Create */
+        if (ein->type == INODE_SYMLINK) {
+            if (++symcount > MAXSYMLINKS) {
+                reply.data1 = ERROR; Reply(&reply, sender); return;
+            }
+            char target[MAXPATHNAMELEN + 1];
+            int tlen = read_symlink(existing, target, MAXPATHNAMELEN);
+            if (tlen <= 0) {
+                reply.data1 = ERROR; Reply(&reply, sender); return;
+            }
+            target[tlen] = '\0';
+
+            /* Resolve the symlink target -- recursive create */
+            int resolved = resolve_path(target, parent_inum, 1, &symcount);
+            if (resolved <= 0) {
+                reply.data1 = ERROR; Reply(&reply, sender); return;
+            }
+            ein = inode_read(resolved);
+            existing = resolved;
+        }
+
+        if (ein->type == INODE_DIRECTORY) {
+            reply.data1 = ERROR; Reply(&reply, sender); return;
+        }
+
+        /* Truncate existing regular file */
+        free_file_blocks(existing);
+        ein = inode_read(existing);
+
+        reply.data1 = 0;          /* size after truncation */
+        reply.data2 = existing;
+        reply.data3 = ein->reuse;
+        Reply(&reply, sender);
+        return;
+    }
+
+    /* Component does not exist — create new file */
+    int new_inum = alloc_inode();
+    if (new_inum == 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *nin = inode_read(new_inum);
+    nin->type     = INODE_REGULAR;
+    nin->nlink    = 1;
+    nin->reuse   += 1;
+    nin->size     = 0;
+    memset(nin->direct, 0, sizeof(nin->direct));
+    nin->indirect = 0;
+    inode_mark_dirty(new_inum);
+
+    if (dir_add(parent_inum, comp, new_inum) != 0) {
+        /* roll back */
+        nin->type = INODE_FREE;
+        inode_mark_dirty(new_inum);
+        release_inode(new_inum);
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    reply.data1 = 0;           /* size = 0 */
+    reply.data2 = new_inum;
+    reply.data3 = nin->reuse;
+    Reply(&reply, sender);
+}
+
+static void handle_read(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    memset(&reply, 0, sizeof(reply));
+
+    int inum     = msg->data1;
+    void *cbuf   = msg->ptr1;
+    int position = (int)(long)msg->ptr2;
+    int reuse    = msg->data2;
+    int size     = msg->data3;
+
+    if (inum < 1 || inum > g_num_inodes || size < 0 || position < 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *in = inode_read(inum);
+    if (in->type == INODE_FREE || in->reuse != reuse) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* Clamp to EOF */
+    int avail = in->size - position;
+    if (avail < 0) avail = 0;
+    if (size > avail) size = avail;
+
+    int done = 0;
+    static char zero_block[BLOCKSIZE];
+
+    while (done < size) {
+        int bidx   = (position + done) / BLOCKSIZE;
+        int offset = (position + done) % BLOCKSIZE;
+        int chunk  = BLOCKSIZE - offset;
+        if (chunk > size - done) chunk = size - done;
+
+        int bn = get_blocknum(in, bidx);
+        char *src;
+        if (bn == 0) {
+            memset(zero_block, 0, BLOCKSIZE);
+            src = zero_block;
+        } else {
+            src = block_read(bn);
+        }
+        CopyTo(sender, (char *)cbuf + done, src + offset, chunk);
+        done += chunk;
+    }
+
+    reply.data1 = done;
+    Reply(&reply, sender);
+}
+
+static void handle_write(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    memset(&reply, 0, sizeof(reply));
+
+    int inum     = msg->data1;
+    void *cbuf   = msg->ptr1;
+    int position = (int)(long)msg->ptr2;
+    int reuse    = msg->data2;
+    int size     = msg->data3;
+
+    if (inum < 1 || inum > g_num_inodes || size < 0 || position < 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *in = inode_read(inum);
+    if (in->type == INODE_FREE || in->reuse != reuse) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    if (in->type == INODE_DIRECTORY) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* Clamp to max file size */
+    if (position + size > MAX_FILE_SIZE)
+        size = MAX_FILE_SIZE - position;
+    if (size <= 0) {
+        reply.data1 = 0; Reply(&reply, sender); return;
+    }
+
+    int done = 0;
+    while (done < size) {
+        int bidx   = (position + done) / BLOCKSIZE;
+        int offset = (position + done) % BLOCKSIZE;
+        int chunk  = BLOCKSIZE - offset;
+        if (chunk > size - done) chunk = size - done;
+
+        int bn = ensure_block(in, inum, bidx);
+        if (bn == 0) break;   /* out of blocks */
+
+        char *bd = block_read(bn);
+        CopyFrom(sender, bd + offset, (char *)cbuf + done, chunk);
+        block_mark_dirty(bn);
+        done += chunk;
+    }
+
+    if (position + done > in->size) {
+        in->size = position + done;
+        inode_mark_dirty(inum);
+    }
+
+    reply.data1 = done;
+    Reply(&reply, sender);
+}
+
+static void handle_link(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    memset(&reply, 0, sizeof(reply));
+
+    char oldname[MAXPATHNAMELEN], newname[MAXPATHNAMELEN];
+    int oldlen = msg->data2, newlen = msg->data3;
+
+    if (oldlen <= 0 || oldlen > MAXPATHNAMELEN ||
+        newlen <= 0 || newlen > MAXPATHNAMELEN) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    if (CopyFrom(sender, oldname, msg->ptr1, oldlen) != 0 ||
+        CopyFrom(sender, newname, msg->ptr2, newlen) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    oldname[oldlen - 1] = '\0';
+    newname[newlen - 1] = '\0';
+
+    int cur_dir = msg->data1;
+
+    /* Resolve oldname (don't follow last symlink) */
+    int symcount = 0;
+    int old_inum = resolve_path(oldname, cur_dir, 0, &symcount);
+    if (old_inum <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *oin = inode_read(old_inum);
+    if (oin->type == INODE_DIRECTORY) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* Split newname */
+    char parent_path[MAXPATHNAMELEN], comp[DIRNAMELEN + 1];
+    if (split_path(newname, parent_path, comp) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    symcount = 0;
+    int parent_inum = resolve_path(parent_path, cur_dir, 1, &symcount);
+    if (parent_inum <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *pin = inode_read(parent_inum);
+    if (pin->type != INODE_DIRECTORY) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* newname must not already exist */
+    if (dir_lookup(parent_inum, comp) > 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    if (dir_add(parent_inum, comp, old_inum) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    oin = inode_read(old_inum);
+    oin->nlink++;
+    inode_mark_dirty(old_inum);
+
+    reply.data1 = 0;
+    Reply(&reply, sender);
+}
+
+static void handle_unlink(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    memset(&reply, 0, sizeof(reply));
+
+    char pathname[MAXPATHNAMELEN];
+    int pathlen = msg->data2;
+
+    if (pathlen <= 0 || pathlen > MAXPATHNAMELEN) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    if (CopyFrom(sender, pathname, msg->ptr1, pathlen) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    pathname[pathlen - 1] = '\0';
+
+    char parent_path[MAXPATHNAMELEN], comp[DIRNAMELEN + 1];
+    if (split_path(pathname, parent_path, comp) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    int cur_dir = msg->data1;
+    int symcount = 0;
+    int parent_inum = resolve_path(parent_path, cur_dir, 1, &symcount);
+    if (parent_inum <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    int found = dir_lookup(parent_inum, comp);
+    if (found <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *fin = inode_read(found);
+    if (fin->type == INODE_DIRECTORY) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    dir_remove(parent_inum, comp);
+
+    fin = inode_read(found);
+    fin->nlink--;
+    inode_mark_dirty(found);
+
+    if (fin->nlink <= 0) {
+        free_file_blocks(found);
+        fin = inode_read(found);
+        fin->type = INODE_FREE;
+        inode_mark_dirty(found);
+        release_inode(found);
+    }
+
+    reply.data1 = 0;
+    Reply(&reply, sender);
+}
+
+static void handle_symlink(int sender, struct yfs_msg *msg)
+{
+    struct yfs_msg reply;
+    memset(&reply, 0, sizeof(reply));
+
+    char oldname[MAXPATHNAMELEN], newname[MAXPATHNAMELEN];
+    int oldlen = msg->data2, newlen = msg->data3;
+
+    if (oldlen <= 0 || oldlen > MAXPATHNAMELEN ||
+        newlen <= 0 || newlen > MAXPATHNAMELEN) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    if (CopyFrom(sender, oldname, msg->ptr1, oldlen) != 0 ||
+        CopyFrom(sender, newname, msg->ptr2, newlen) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+    oldname[oldlen - 1] = '\0';
+    newname[newlen - 1] = '\0';
+
+    /* oldname must not be empty */
+    if (strlen(oldname) == 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    int cur_dir = msg->data1;
+
+    /* Split newname */
+    char parent_path[MAXPATHNAMELEN], comp[DIRNAMELEN + 1];
+    if (split_path(newname, parent_path, comp) != 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    int symcount = 0;
+    int parent_inum = resolve_path(parent_path, cur_dir, 1, &symcount);
+    if (parent_inum <= 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    struct inode *pin = inode_read(parent_inum);
+    if (pin->type != INODE_DIRECTORY) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* newname must not already exist */
+    if (dir_lookup(parent_inum, comp) > 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* Allocate inode for symlink */
+    int new_inum = alloc_inode();
+    if (new_inum == 0) {
+        reply.data1 = ERROR; Reply(&reply, sender); return;
+    }
+
+    /* Write the target pathname as the symlink's data */
+    int target_len = strlen(oldname);
+
+    struct inode *nin = inode_read(new_inum);
+    nin->type     = INODE_SYMLINK;
+    nin->nlink    = 1;
+    nin->reuse   += 1;
+    nin->size     = 0;
+    memset(nin->direct, 0, sizeof(nin->direct));
+    nin->indirect = 0;
+    inode_mark_dirty(new_inum);
+
+    /* Write target string into symlink's data blocks */
+    int done = 0;
+    while (done < target_len) {
+        int bidx   = done / BLOCKSIZE;
